const documents = [
  { id: 'ifrs', text: 'IFRS control logic and accounting rules.' },
  { id: 'eu_ai_act', text: 'EU AI Act controls for high-risk AI systems.' },
  { id: 'audit_template', text: 'Audit issue templates for bug4Audit and compliance findings.' }
];
return documents.map(doc => ({ json: doc }));

const query = items[0].json.query || 'audit controls';
const results = items[0].json.corpus.filter(doc => doc.text.toLowerCase().includes('ifrs') || doc.text.toLowerCase().includes('eu ai act'));
return results.map(doc => ({ json: { source: doc.id, snippet: doc.text } }));

const query = items[0].json.query || 'Provide audit review guidance for BERT and cybersecurity.';
const docs = items.map(item => item.json.snippet).join('

');
return [{ json: { prompt: `Use the following reference documents to answer the auditor query:

${docs}

Query: ${query}` } }];
